import pytest

def test_submit_timesheet_valid_midrange_emits_webhook(
    auth_token, api_client, webhook_listener, draft_timesheet
):
    payload = {
        "timesheet_id": draft_timesheet["id"],
        "days": [
            {"day": d, "hours": 8}
            for d in ["mon", "tue", "wed", "thu", "fri", "sat", "sun"]
        ],
    }
    resp = api_client.post(
        "/timesheets/submit",
        json=payload,
        headers={"Authorization": f"Bearer {auth_token}"},
    )
    assert resp.status_code in (200, 201), resp.text
    body = resp.json()
    assert body["state"] == "submitted"
    event = webhook_listener.wait_for_event(
        event_type="timesheet.submitted", timeout=5
    )
    assert event is not None
    assert event["timesheet_id"] == draft_timesheet["id"]

