def test_submit_timesheet_weekly_total_exceeds_80_returns_422(
    auth_token, api_client, draft_timesheet
):
    # 7 days * 12 = 84 hours; each day <= 24 so per-day rule passes
    payload = {
        "timesheet_id": draft_timesheet["id"],
        "days": [
            {"day": d, "hours": 12}
            for d in ["mon", "tue", "wed", "thu", "fri", "sat", "sun"]
        ],
    }
    resp = api_client.post(
        "/timesheets/submit",
        json=payload,
        headers={"Authorization": f"Bearer {auth_token}"},
    )
    assert resp.status_code == 422, resp.text
    error_body = resp.json()
    assert "total" in str(error_body).lower() or "weekly" in str(error_body).lower()
    state_resp = api_client.get(
        f"/timesheets/{draft_timesheet['id']}",
        headers={"Authorization": f"Bearer {auth_token}"},
    )
    assert state_resp.json()["state"] == "draft"

