def test_submit_timesheet_boundary_max_day_and_max_week(
    auth_token, api_client, draft_timesheet
):
    # Mon-Thu: 20h each = 80h total; Fri-Sun: 0h; all per-day <= 24
    hours_map = {"mon": 20, "tue": 20, "wed": 20, "thu": 20, "fri": 0, "sat": 0, "sun": 0}
    payload = {
        "timesheet_id": draft_timesheet["id"],
        "days": [{"day": d, "hours": h} for d, h in hours_map.items()],
    }
    resp = api_client.post(
        "/timesheets/submit",
        json=payload,
        headers={"Authorization": f"Bearer {auth_token}"},
    )
    assert resp.status_code in (200, 201), resp.text
    assert resp.json()["state"] == "submitted"

