import pytest

def test_submit_timesheet_state_transition_draft_to_submitted(
    auth_token, api_client, draft_timesheet
):
    headers = {"Authorization": f"Bearer {auth_token}"}
    pre = api_client.get(f"/timesheets/{draft_timesheet['id']}", headers=headers)
    assert pre.json()["state"] == "draft"
    payload = {
        "timesheet_id": draft_timesheet["id"],
        "days": [
            {"day": d, "hours": 7}
            for d in ["mon", "tue", "wed", "thu", "fri", "sat", "sun"]
        ],
    }
    submit = api_client.post("/timesheets/submit", json=payload, headers=headers)
    assert submit.status_code in (200, 201), submit.text
    post = api_client.get(f"/timesheets/{draft_timesheet['id']}", headers=headers)
    assert post.json()["state"] == "submitted"
